mapper.select:
select event_id,depart_member_id,is_notify,is_assigned,assigned_time,notify_time,create_time
from event_depart_member
where event_id = #{eventId}
and depart_member_id = #{departMemberId}

SELECT
edm.*
FROM event_info ei
LEFT JOIN event_depart_member edm ON ei.id = edm.event_id
LEFT JOIN department_info di ON edm.depart_member_id = di.leader AND di.id = #{departId}
WHERE ei.id = #{eventId}
